+		},
+		{
+			name:            "hostNetwork true, should set hostNetwork and DNSPolicy",
+			hostNetwork:     ptr.To(true),
+			expectEnabled:   true,
+			expectDNSPolicy: corev1.DNSClusterFirstWithHostNet,
