+func TestExtractEnvVars(t *testing.T) {
+	tests := []struct {
+		name     string
+		input    []corev1.EnvVar
+		expected []EnvVar
+	}{
+		{
+			name:     "nil input",
+			input:    nil,
+			expected: nil,
+		},
+		{
+			name:     "empty input",
+			input:    []corev1.EnvVar{},
+			expected: nil,
+		},
+		{
+			name: "direct values only",
+			input: []corev1.EnvVar{
+				{Name: "B_VAR", Value: "b-val"},
+				{Name: "A_VAR", Value: "a-val"},
+			},
+			expected: []EnvVar{
+				{Name: "A_VAR", Value: "a-val"},
+				{Name: "B_VAR", Value: "b-val"},
+			},
+		},
+		{
+			name: "ValueFrom entries are skipped",
+			input: []corev1.EnvVar{
+				{Name: "DIRECT", Value: "yes"},
+				{Name: "NODE_NAME", ValueFrom: &corev1.EnvVarSource{
+					FieldRef: &corev1.ObjectFieldSelector{FieldPath: "spec.nodeName"},
+				}},
+				{Name: "SECRET_VAL", ValueFrom: &corev1.EnvVarSource{
+					SecretKeyRef: &corev1.SecretKeySelector{
+						LocalObjectReference: corev1.LocalObjectReference{Name: "my-secret"},
+						Key:                  "key",
+					},
+				}},
+			},
+			expected: []EnvVar{
+				{Name: "DIRECT", Value: "yes"},
+			},
+		},
+		{
+			name: "all ValueFrom entries",
+			input: []corev1.EnvVar{
+				{Name: "NODE_NAME", ValueFrom: &corev1.EnvVarSource{
+					FieldRef: &corev1.ObjectFieldSelector{FieldPath: "spec.nodeName"},
+				}},
+			},
+			expected: nil,
+		},
+		{
+			name: "empty string Value is kept",
+			input: []corev1.EnvVar{
+				{Name: "EMPTY_VAL", Value: ""},
+			},
+			expected: []EnvVar{
+				{Name: "EMPTY_VAL", Value: ""},
+			},
+		},
+		{
+			name: "mixed entries sorted by name",
+			input: []corev1.EnvVar{
+				{Name: "ZEBRA", Value: "z"},
+				{Name: "NODE_IP", ValueFrom: &corev1.EnvVarSource{
+					FieldRef: &corev1.ObjectFieldSelector{FieldPath: "status.hostIP"},
+				}},
+				{Name: "ALPHA", Value: "a"},
+				{Name: "MIDDLE", Value: "m"},
+			},
+			expected: []EnvVar{
+				{Name: "ALPHA", Value: "a"},
+				{Name: "MIDDLE", Value: "m"},
+				{Name: "ZEBRA", Value: "z"},
+			},
+		},
+	}
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
+			result := ExtractEnvVars(tc.input)
+			assert.Equal(t, tc.expected, result)
+		})
+	}
+}
+
+func TestSortEnvVars(t *testing.T) {
+	tests := []struct {
+		name     string
+		input    []EnvVar
+		expected []EnvVar
+	}{
+		{
+			name:     "nil input",
+			input:    nil,
+			expected: nil,
+		},
+		{
+			name:     "empty input",
+			input:    []EnvVar{},
+			expected: []EnvVar{},
+		},
+		{
+			name:     "single element",
+			input:    []EnvVar{{Name: "A", Value: "1"}},
+			expected: []EnvVar{{Name: "A", Value: "1"}},
+		},
+		{
+			name: "already sorted",
+			input: []EnvVar{
+				{Name: "A", Value: "1"},
+				{Name: "B", Value: "2"},
+			},
+			expected: []EnvVar{
+				{Name: "A", Value: "1"},
+				{Name: "B", Value: "2"},
+			},
+		},
+		{
+			name: "reverse order",
+			input: []EnvVar{
+				{Name: "C", Value: "3"},
+				{Name: "B", Value: "2"},
+				{Name: "A", Value: "1"},
+			},
+			expected: []EnvVar{
+				{Name: "A", Value: "1"},
+				{Name: "B", Value: "2"},
+				{Name: "C", Value: "3"},
+			},
+		},
+	}
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
+			result := SortEnvVars(tc.input)
+			assert.Equal(t, tc.expected, result)
+		})
+	}
+
+	t.Run("does not mutate input", func(t *testing.T) {
+		input := []EnvVar{
+			{Name: "B", Value: "2"},
+			{Name: "A", Value: "1"},
+		}
+		original := make([]EnvVar, len(input))
+		copy(original, input)
+
+		_ = SortEnvVars(input)
+		assert.Equal(t, original, input, "input slice must not be mutated")
+	})
+}
